import{_ as e,a as o}from"./chunks/layout-editor-panel-dark.BIiFq4Mb.js";import{_ as a,a as r}from"./chunks/theme-tools-modal-dark.BOEnm2cB.js";import{_ as s,o as i,c as l,ag as n}from"./chunks/framework.DmiIFzQJ.js";const d="/docs/selection-tool-icon-light.png",c="/docs/selection-tool-icon-dark.png",h="/docs/move-exactly-tool-icon-light.png",g="/docs/move-exactly-tool-icon-dark.png",m="/docs/rotate-selection-tool-icon-light.png",b="/docs/rotate-selection-tool-icon-dark.png",k="/docs/mirror-tool-icon-light.png",p="/docs/mirror-tool-icon-dark.png",y="/docs/extra-tools-icon-light.png",u="/docs/extra-tools-icon-dark.png",f="/docs/key-selection.gif",x="/docs/canvas-footer-left.png",v="/docs/mouse-move.gif",w="/docs/lock-rotation-disabled-small.gif",_="/docs/lock-rotation-enabled-small.gif",T="/docs/move-with-tool.gif",C="/docs/move-exactly-mm-light.png",S="/docs/move-exactly-mm-dark.png",M="/docs/rotate-tool.gif",q="/docs/mirror-tool.gif",P="/docs/legend-tools-edit.gif",L="/docs/legend-tools-move.gif",A="/docs/add-switch-matrix-coordinates-modal-light.png",E="/docs/add-switch-matrix-coordinates-modal-dark.png",R="/docs/manual-annotation-draw-row.gif",D="/docs/manual-annotation-draw-columns.gif",N="/docs/manual-annotation-remove-elements.gif",Y=JSON.parse('{"title":"Layout Editor","description":"","frontmatter":{},"headers":[],"relativePath":"layout-editor.md","filePath":"layout-editor.md"}'),U={name:"layout-editor.md"};function I(O,t,K,V,z,G){return i(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="layout-editor" tabindex="-1">Layout Editor <a class="header-anchor" href="#layout-editor" aria-label="Permalink to &quot;Layout Editor&quot;">​</a></h1><p>The canvas editor is the main working area of kle-ng. It provides a full set of tools for creating and editing keyboard layouts.</p><img src="'+e+'" class="docs-screenshot light-only" alt="Layout editor canvas with a keyboard layout"><img src="'+o+'" class="docs-screenshot dark-only" alt="Layout editor canvas with a keyboard layout"><h2 id="canvas-tools" tabindex="-1">Canvas Tools <a class="header-anchor" href="#canvas-tools" aria-label="Permalink to &quot;Canvas Tools&quot;">​</a></h2><p>The toolbar on the left side of the canvas contains the main editing tools:</p><table tabindex="0"><thead><tr><th style="text-align:center;">Icon</th><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td style="text-align:center;"><img src="'+d+'" class="light-only" alt=""><img src="'+c+'" class="dark-only" alt=""></td><td><a href="#selection-tool"><strong>Selection Tool</strong></a></td><td>Select, move, resize keys</td></tr><tr><td style="text-align:center;"><img src="'+h+'" class="light-only" alt=""><img src="'+g+'" class="dark-only" alt=""></td><td><a href="#move-exactly-tool"><strong>Move Exactly Tool</strong></a></td><td>Move keys by a precise amount</td></tr><tr><td style="text-align:center;"><img src="'+m+'" class="light-only" alt=""><img src="'+b+'" class="dark-only" alt=""></td><td><a href="#rotate-selection-tool"><strong>Rotate Selection Tool</strong></a></td><td>Rotate selected keys around anchor points</td></tr><tr><td style="text-align:center;"><img src="'+k+'" class="light-only" alt=""><img src="'+p+'" class="dark-only" alt=""></td><td><a href="#mirror-tool"><strong>Mirror Tool</strong></a></td><td>Create mirrored copies of selected keys</td></tr><tr><td style="text-align:center;"><img src="'+y+'" class="light-only" alt=""><img src="'+u+'" class="dark-only" alt=""></td><td><a href="#extra-tools"><strong>Extra Tools</strong></a></td><td><a href="#legend-tools">Legend Tools</a>, <a href="#add-switch-matrix-coordinates">Matrix Coordinates</a>, <a href="#move-rotation-origins">Move Rotation Origins</a>, <a href="#theme-tools">Theme Tools</a></td></tr></tbody></table><h2 id="mouse-controls" tabindex="-1">Mouse Controls <a class="header-anchor" href="#mouse-controls" aria-label="Permalink to &quot;Mouse Controls {#mouse-controls}&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Result</th></tr></thead><tbody><tr><td><strong>Left Click</strong></td><td>Select a key</td></tr><tr><td><strong>Left Click + Drag</strong></td><td>Create a rectangle selection</td></tr><tr><td><strong>Ctrl + Left Click</strong></td><td>Add/remove key from selection</td></tr><tr><td><strong>Middle Click + Drag</strong></td><td>Move selected keys</td></tr></tbody></table><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard Shortcuts {#keyboard-shortcuts}&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><kbd>Ctrl</kbd>+<kbd>C</kbd></td><td>Copy selected keys</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>V</kbd></td><td>Paste keys from clipboard</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd></td><td>Cut selected keys</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>A</kbd></td><td>Select all keys</td></tr><tr><td><kbd>Del</kbd> / <kbd>Backspace</kbd></td><td>Delete selected keys</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>Z</kbd></td><td>Undo last action</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>]</kbd></td><td>Select next key</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>[</kbd></td><td>Select previous key</td></tr><tr><td><kbd>Arrow keys</kbd></td><td>Nudge selected keys</td></tr><tr><td><kbd>Shift</kbd>+<kbd>←</kbd><kbd>→</kbd></td><td>Adjust key width</td></tr><tr><td><kbd>Shift</kbd>+<kbd>↑</kbd><kbd>↓</kbd></td><td>Adjust key height</td></tr><tr><td><kbd>A</kbd></td><td>Add new key</td></tr><tr><td><kbd>/</kbd></td><td>Toggle label search bar</td></tr><tr><td><kbd>Shift</kbd>+<kbd>M</kbd></td><td>Open <a href="#move-exactly-tool">Move Exactly Tool</a></td></tr><tr><td><kbd>Shift</kbd>+<kbd>R</kbd></td><td>Open <a href="#rotate-selection-tool">Rotate Selection Tool</a></td></tr></tbody></table><h2 id="selection-tool" tabindex="-1">Selection Tool <a class="header-anchor" href="#selection-tool" aria-label="Permalink to &quot;Selection Tool {#selection-tool}&quot;">​</a></h2><p>The Selection Tool is the default tool for working with keys.</p><h3 id="selecting-keys" tabindex="-1">Selecting Keys <a class="header-anchor" href="#selecting-keys" aria-label="Permalink to &quot;Selecting Keys&quot;">​</a></h3><div style="display:flex;gap:1.5rem;align-items:flex-start;"><ul><li>Click a key to select it</li><li>Click and drag on empty canvas area to draw a rectangle selection</li><li>Hold <kbd>Ctrl</kbd> while clicking to add or remove keys from the current selection</li><li>Use <kbd>Ctrl</kbd>+<kbd>[</kbd> and <kbd>Ctrl</kbd>+<kbd>]</kbd> to cycle through keys in layout order</li></ul><img src="'+f+'" alt="Key selection animation" style="flex-shrink:0;max-width:220px;"></div><h3 id="moving-keys" tabindex="-1">Moving Keys <a class="header-anchor" href="#moving-keys" aria-label="Permalink to &quot;Moving Keys&quot;">​</a></h3><div style="display:flex;gap:1.5rem;align-items:flex-start;"><div><ul><li><strong>Middle mouse button</strong>: Click and drag to move the selection</li><li><strong>Arrow keys</strong>: Nudge selected keys by the configured step size</li></ul><p>Movement snaps to a configurable step size (defined in U, where 1U = width of a standard key). The step size can be set in the canvas footer.</p><img src="'+x+'" alt="Canvas footer controls" class="docs-screenshot"></div><img src="'+v+'" alt="Mouse movement animation" style="flex-shrink:0;max-width:220px;"></div><h3 id="lock-rotations" tabindex="-1">Lock Rotations <a class="header-anchor" href="#lock-rotations" aria-label="Permalink to &quot;Lock Rotations&quot;">​</a></h3><p>The <strong>Lock rotations</strong> option determines how rotated keys move:</p><table tabindex="0"><thead><tr><th style="text-align:center;">Lock Disabled</th><th style="text-align:center;">Lock Enabled</th></tr></thead><tbody><tr><td style="text-align:center;"><img src="'+w+'" alt="Lock disabled"></td><td style="text-align:center;"><img src="'+_+'" alt="Lock enabled"></td></tr><tr><td style="text-align:center;">Rotation origin stays fixed; keys move in rotated coordinate space</td><td style="text-align:center;">Rotation origin moves with the keys; movement occurs in normal coordinate space</td></tr></tbody></table><h2 id="move-exactly-tool" tabindex="-1">Move Exactly Tool <a class="header-anchor" href="#move-exactly-tool" aria-label="Permalink to &quot;Move Exactly Tool&quot;">​</a></h2><p>For precise movement use the <strong>Move Exactly</strong> tool (<kbd>Shift</kbd>+<kbd>M</kbd>).</p><p>The tool allows movement to any position, not limited to the step size. It also supports movement in <strong>millimeters</strong> by specifying the spacing (mm per U). The default spacing is <strong>19.05 mm/U</strong> for both X and Y axes, which is standard for Cherry MX style switches.</p><h3 id="using-the-tool" tabindex="-1">Using the Tool <a class="header-anchor" href="#using-the-tool" aria-label="Permalink to &quot;Using the Tool&quot;">​</a></h3><div style="display:flex;gap:1.5rem;align-items:flex-start;"><img src="'+T+'" alt="Move exactly tool animation" style="flex:2;min-width:0;max-width:66%;"><img src="'+C+'" alt="Move exactly mm panel" class="docs-screenshot light-only" style="flex:1;min-width:0;max-width:34%;"><img src="'+S+'" alt="Move exactly mm panel" class="docs-screenshot dark-only" style="flex:1;min-width:0;max-width:34%;"></div><h2 id="rotate-selection-tool" tabindex="-1">Rotate Selection Tool <a class="header-anchor" href="#rotate-selection-tool" aria-label="Permalink to &quot;Rotate Selection Tool&quot;">​</a></h2><p>Rotate selected keys around anchor points (key corners and centers) using the <strong>Rotate Selection</strong> tool (<kbd>Shift</kbd>+<kbd>R</kbd>).</p><h3 id="using-the-tool-1" tabindex="-1">Using the Tool <a class="header-anchor" href="#using-the-tool-1" aria-label="Permalink to &quot;Using the Tool&quot;">​</a></h3><p><img src="'+M+'" alt="Rotate tool animation"></p><h2 id="mirror-tool" tabindex="-1">Mirror Tool <a class="header-anchor" href="#mirror-tool" aria-label="Permalink to &quot;Mirror Tool&quot;">​</a></h2><p>Create mirrored copies of selected keys with the <strong>Mirror Tool</strong>. Choose a mirror axis position — the axis snaps to multiples of the step size. Supports both vertical (default) and horizontal mirroring from the tool dropdown.</p><h3 id="using-the-tool-2" tabindex="-1">Using the Tool <a class="header-anchor" href="#using-the-tool-2" aria-label="Permalink to &quot;Using the Tool&quot;">​</a></h3><p><img src="'+q+'" alt="Mirror tool animation"></p><h2 id="extra-tools" tabindex="-1">Extra Tools <a class="header-anchor" href="#extra-tools" aria-label="Permalink to &quot;Extra Tools {#extra-tools}&quot;">​</a></h2><p>Extra tools are grouped under a single button in the left toolbar. There are four:</p><ol><li><strong>Legend Tools</strong> — bulk legend editing</li><li><strong>Add Switch Matrix Coordinates</strong> — assign VIA-style row/column labels</li><li><strong>Move Rotation Origins</strong> — recalculate key positions with a new rotation reference point</li><li><strong>Theme Tools</strong> — apply color themes to the layout</li></ol><h3 id="legend-tools" tabindex="-1">Legend Tools <a class="header-anchor" href="#legend-tools" aria-label="Permalink to &quot;Legend Tools&quot;">​</a></h3><p>Legend tools provide quick canvas-oriented label editing in four modes:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td><strong>Edit</strong></td><td>Direct label assignment with auto-advancement to next key after <kbd>Enter</kbd></td></tr><tr><td><strong>Remove</strong></td><td>Remove all labels at the selected label position</td></tr><tr><td><strong>Align</strong></td><td>Change label alignment</td></tr><tr><td><strong>Move</strong></td><td>Move labels from one position to another</td></tr></tbody></table><table tabindex="0"><thead><tr><th style="text-align:center;">Edit Mode</th><th style="text-align:center;">Move Mode</th></tr></thead><tbody><tr><td style="text-align:center;"><img src="'+P+'" alt="Legend tools edit"></td><td style="text-align:center;"><img src="'+L+'" alt="Legend tools move"></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Legend Tools are designed for easier bulk label editing compared to modifying labels one at a time in the Key Properties panel.</p></div><h3 id="add-switch-matrix-coordinates" tabindex="-1">Add Switch Matrix Coordinates <a class="header-anchor" href="#add-switch-matrix-coordinates" aria-label="Permalink to &quot;Add Switch Matrix Coordinates&quot;">​</a></h3><p>This tool assigns VIA-style <code>row,column</code> labels (e.g., <code>0,0</code>) to each key, enabling compatibility with <a href="https://www.caniusevia.com/" target="_blank" rel="noreferrer">VIA</a> and <a href="https://get.vial.today/" target="_blank" rel="noreferrer">Vial</a> configurators and the <a href="./pcb-generator.html">PCB Generator</a>.</p><img src="'+A+'" alt="Switch Matrix Coordinates Window" class="light-only" style="flex-shrink:0;width:50%;"><img src="'+E+'" alt="Switch Matrix Coordinates Window" class="dark-only" style="flex-shrink:0;width:50%;"><p>The tool provides an <strong>Annotate Automatically</strong> option that assigns coordinates intelligently based on key positions. You can also draw rows and columns manually:</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Automatic annotations may not produce correct results for certain keyboard layouts. <strong>Ergonomic layouts with significant column splay</strong> (angled columns) are particularly affected and may require manual correction of row/column assignments. Standard rectangular layouts typically produce good results. See <a href="https://github.com/adamws/kle-ng/issues/51" target="_blank" rel="noreferrer">issue #51</a> for details.</p></div><table tabindex="0"><thead><tr><th style="text-align:center;">Draw Rows</th><th style="text-align:center;">Draw Columns</th><th style="text-align:center;">Remove</th></tr></thead><tbody><tr><td style="text-align:center;"><img src="'+R+'" alt="Draw rows"></td><td style="text-align:center;"><img src="'+D+'" alt="Draw columns"></td><td style="text-align:center;"><img src="'+N+'" alt="Remove"></td></tr></tbody></table><ul><li>Left-click to start and complete wire segments</li><li>Right-click or <kbd>Escape</kbd> to cancel</li><li>Click an existing wire to append to it</li><li>Hold <kbd>Ctrl</kbd> while clicking a wire to remove the entire row/column</li></ul><p>To renumber a row or column: hover over it in any editing mode and type the new number.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To export a PNG with the matrix wire overlay visible, open the <strong>Add Switch Matrix Coordinates</strong> tool first, then use <strong>Export → Download PNG</strong>.</p></div><h3 id="move-rotation-origins" tabindex="-1">Move Rotation Origins <a class="header-anchor" href="#move-rotation-origins" aria-label="Permalink to &quot;Move Rotation Origins&quot;">​</a></h3><p>The <strong>Move Rotation Origins</strong> tool reassigns the rotation origin point for keys without changing their visual position on the canvas. This is useful when you want to reference a different pivot point for subsequent rotations — for example, after repositioning a key cluster, you may want the rotation origin to be the new key center rather than the original one.</p><p>The tool operates on selected keys, or on all keys if nothing is selected. Two modes are available:</p><ul><li><strong>Use key centers</strong> — Calculates and sets the rotation origin to the geometric center of each key individually.</li><li><strong>Manual position</strong> — Sets the rotation origin to a fixed X/Y coordinate (in U) for all affected keys.</li></ul><h3 id="theme-tools" tabindex="-1">Theme Tools <a class="header-anchor" href="#theme-tools" aria-label="Permalink to &quot;Theme Tools&quot;">​</a></h3><p>The <strong>Theme Tools</strong> panel applies color themes to the entire layout in bulk. Open it from <strong>Extra Tools → Theme Tools</strong>.</p><img src="'+a+'" class="light-only" alt="Theme tools modal"><img src="'+r+'" class="dark-only" alt="Theme tools modal"><p>Choose from several built-in themes in the dropdown:</p><table tabindex="0"><thead><tr><th>Theme</th><th>Description</th></tr></thead><tbody><tr><td>Classic</td><td>Light gray keys on a gray background — the classic KLE look</td></tr><tr><td>Dark</td><td>Dark gray keys on a near-black background</td></tr><tr><td>VIA</td><td>Light gray alphas with darker modifiers, similar to VIA&#39;s default display</td></tr><tr><td>Gruvbox (dark)</td><td>Gruvbox color palette with dark background</td></tr></tbody></table><p>Themes are defined as JSON objects with named rules and matcher expressions that target specific keys. You can edit the current theme directly in the JSON editor within the panel, or load and save theme files using <strong>Load JSON</strong> and <strong>Save JSON</strong>.</p><p>The panel also includes a <strong>Color Calculator</strong> for converting between stored KLE keycap colors and the rendered key-top colors.</p><p>See <a href="./color-themes.html">Color Themes</a> for the full theme format, matcher syntax reference, and examples.</p><h2 id="label-search" tabindex="-1">Label Search <a class="header-anchor" href="#label-search" aria-label="Permalink to &quot;Label Search {#label-search}&quot;">​</a></h2><p>Press <kbd>/</kbd> to open the label search bar. Type to find keys by their label text. Matches are highlighted on the canvas. Use <kbd>Enter</kbd> or the up/down arrows to cycle through matches. Press <kbd>Escape</kbd> or <kbd>/</kbd> again to close.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To export a PNG with search match highlighting visible, keep the search bar open before using <strong>Export → Download PNG</strong>.</p></div><h2 id="canvas-settings" tabindex="-1">Canvas Settings <a class="header-anchor" href="#canvas-settings" aria-label="Permalink to &quot;Canvas Settings {#canvas-settings}&quot;">​</a></h2><p>A settings panel is accessible from the toolbar (gear icon). Current settings:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Show grid</strong></td><td>Toggles a dot grid on the canvas aligned to the current step size</td></tr><tr><td><strong>Highlight Color</strong></td><td>Color used to indicate selected keys. Click the swatch to change it</td></tr></tbody></table>',70)])])}const $=s(U,[["render",I]]);export{Y as __pageData,$ as default};
